public int[] twoSum(int[] numbers, int target) {
    int left = 0, right = numbers.length - 1;
    while (left < right) {
        int sum = numbers[left] + numbers[right];
        if (sum == target) return new int[]{left+1, right+1};
        else if (sum < target) left++;
        else right--;
    }
    return new int[]{-1, -1};
}

public List<List<Integer>> threeSum(int[] nums) {
    Arrays.sort(nums);
    List<List<Integer>> res = new ArrayList<>();
    for (int i = 0; i < nums.length - 2; i++) {
        if (i > 0 && nums[i] == nums[i-1]) continue;
        int l = i+1, r = nums.length-1;
        while (l < r) {
            int sum = nums[i]+nums[l]+nums[r];
            if (sum == 0) {
                res.add(Arrays.asList(nums[i],nums[l],nums[r]));
                while (l < r && nums[l]==nums[l+1]) l++;
                while (l < r && nums[r]==nums[r-1]) r--;
                l++; r--;
            } else if (sum < 0) l++;
            else r--;
        }
    }
    return res;
}

public int maxArea(int[] height) {
    int l = 0, r = height.length-1, max = 0;
    while (l < r) {
        max = Math.max(max, Math.min(height[l],height[r])*(r-l));
        if (height[l] < height[r]) l++;
        else r--;
    }
    return max;
}

public int removeDuplicates(int[] nums) {
    int slow = 1;
    for (int fast = 1; fast < nums.length; fast++) {
        if (nums[fast] != nums[fast-1]) {
            nums[slow++] = nums[fast];
        }
    }
    return slow;
}

public boolean isPalindrome(String s) {
    int l = 0, r = s.length()-1;
    while (l < r) {
        while (l < r && !Character.isLetterOrDigit(s.charAt(l))) l++;
        while (l < r && !Character.isLetterOrDigit(s.charAt(r))) r--;
        if (Character.toLowerCase(s.charAt(l)) != Character.toLowerCase(s.charAt(r))) return false;
        l++; r--;
    }
    return true;
}

public int lengthOfLongestSubstring(String s) {
    Map<Character,Integer> map = new HashMap<>();
    int max = 0, left = 0;
    for (int right = 0; right < s.length(); right++) {
        char c = s.charAt(right);
        if (map.containsKey(c) && map.get(c) >= left) {
            left = map.get(c) + 1;
        }
        map.put(c, right);
        max = Math.max(max, right - left + 1);
    }
    return max;
}

public String minWindow(String s, String t) {
    Map<Character,Integer> need = new HashMap<>();
    for (char c : t.toCharArray()) need.merge(c, 1, Integer::sum);
    int left=0, matched=0, minLen=Integer.MAX_VALUE, start=0;
    Map<Character,Integer> window = new HashMap<>();
    for (int right=0; right<s.length(); right++) {
        char c = s.charAt(right);
        window.merge(c, 1, Integer::sum);
        if (need.containsKey(c) && window.get(c).equals(need.get(c))) matched++;
        while (matched == need.size()) {
            if (right-left+1 < minLen) { minLen=right-left+1; start=left; }
            char l = s.charAt(left);
            window.merge(l, -1, Integer::sum);
            if (need.containsKey(l) && window.get(l) < need.get(l)) matched--;
            left++;
        }
    }
    return minLen==Integer.MAX_VALUE ? "" : s.substring(start, start+minLen);
}

public int characterReplacement(String s, int k) {
    int[] count = new int[26];
    int left=0, maxFreq=0, max=0;
    for (int right=0; right<s.length(); right++) {
        count[s.charAt(right)-'A']++;
        maxFreq = Math.max(maxFreq, count[s.charAt(right)-'A']);
        if (right-left+1 - maxFreq > k) {
            count[s.charAt(left)-'A']--;
            left++;
        }
        max = Math.max(max, right-left+1);
    }
    return max;
}

public int maxSumSubarray(int[] nums, int k) {
    int sum = 0, max = Integer.MIN_VALUE;
    for (int i = 0; i < nums.length; i++) {
        sum += nums[i];
        if (i >= k) sum -= nums[i-k];
        if (i >= k-1) max = Math.max(max, sum);
    }
    return max;
}

public boolean checkInclusion(String s1, String s2) {
    if (s1.length() > s2.length()) return false;
    int[] need = new int[26], window = new int[26];
    for (char c : s1.toCharArray()) need[c-'a']++;
    for (int i = 0; i < s2.length(); i++) {
        window[s2.charAt(i)-'a']++;
        if (i >= s1.length()) window[s2.charAt(i-s1.length())-'a']--;
        if (Arrays.equals(need, window)) return true;
    }
    return false;
}

public int search(int[] nums, int target) {
    int left = 0, right = nums.length-1;
    while (left <= right) {
        int mid = left + (right-left)/2;
        if (nums[mid] == target) return mid;
        else if (nums[mid] < target) left = mid+1;
        else right = mid-1;
    }
    return -1;
}

public int search(int[] nums, int target) {
    int left=0, right=nums.length-1;
    while (left <= right) {
        int mid = left+(right-left)/2;
        if (nums[mid]==target) return mid;
        if (nums[left] <= nums[mid]) {
            if (nums[left]<=target && target<nums[mid]) right=mid-1;
            else left=mid+1;
        } else {
            if (nums[mid]<target && target<=nums[right]) left=mid+1;
            else right=mid-1;
        }
    }
    return -1;
}

public int findPeakElement(int[] nums) {
    int left=0, right=nums.length-1;
    while (left < right) {
        int mid = left+(right-left)/2;
        if (nums[mid] < nums[mid+1]) left=mid+1;
        else right=mid;
    }
    return left;
}

public double findMedianSortedArrays(int[] A, int[] B) {
    if (A.length > B.length) return findMedianSortedArrays(B, A);
    int m=A.length, n=B.length, half=(m+n+1)/2;
    int lo=0, hi=m;
    while (lo <= hi) {
        int i=lo+(hi-lo)/2, j=half-i;
        if (i<m && B[j-1]>A[i]) lo=i+1;
        else if (i>0 && A[i-1]>B[j]) hi=i-1;
        else {
            int maxL = (i==0)?B[j-1]:((j==0)?A[i-1]:Math.max(A[i-1],B[j-1]));
            if ((m+n)%2==1) return maxL;
            int minR = (i==m)?B[j]:((j==n)?A[i]:Math.min(A[i],B[j]));
            return (maxL+minR)/2.0;
        }
    }
    return 0;
}

public int minEatingSpeed(int[] piles, int h) {
    int lo=1, hi=Arrays.stream(piles).max().getAsInt();
    while (lo < hi) {
        int mid=lo+(hi-lo)/2;
        long time=0;
        for (int p : piles) time += (p+mid-1)/mid;
        if (time <= h) hi=mid;
        else lo=mid+1;
    }
    return lo;
}

public int numIslands(char[][] grid) {
    int count=0;
    for (int i=0; i<grid.length; i++)
        for (int j=0; j<grid[0].length; j++)
            if (grid[i][j]=='1') { dfs(grid,i,j); count++; }
    return count;
}
void dfs(char[][] g, int i, int j) {
    if (i<0||i>=g.length||j<0||j>=g[0].length||g[i][j]!='1') return;
    g[i][j]='0';
    dfs(g,i+1,j); dfs(g,i-1,j); dfs(g,i,j+1); dfs(g,i,j-1);
}

public int orangesRotting(int[][] grid) {
    Queue<int[]> q = new LinkedList<>();
    int fresh=0, rows=grid.length, cols=grid[0].length;
    for (int i=0;i<rows;i++) for (int j=0;j<cols;j++) {
        if (grid[i][j]==2) q.offer(new int[]{i,j});
        if (grid[i][j]==1) fresh++;
    }
    int min=0;
    int[][] dirs={{1,0},{-1,0},{0,1},{0,-1}};
    while (!q.isEmpty() && fresh>0) {
        min++;
        for (int s=q.size();s>0;s--) {
            int[] cur=q.poll();
            for (int[] d:dirs) {
                int r=cur[0]+d[0],c=cur[1]+d[1];
                if (r>=0&&r<rows&&c>=0&&c<cols&&grid[r][c]==1) {
                    grid[r][c]=2; fresh--; q.offer(new int[]{r,c});
                }
            }
        }
    }
    return fresh==0?min:-1;
}

public int ladderLength(String beginWord, String endWord, List<String> wordList) {
    Set<String> wordSet = new HashSet<>(wordList);
    if (!wordSet.contains(endWord)) return 0;
    Queue<String> q = new LinkedList<>();
    q.offer(beginWord);
    int level=1;
    while (!q.isEmpty()) {
        for (int s=q.size();s>0;s--) {
            String word=q.poll();
            char[] chars=word.toCharArray();
            for (int i=0;i<chars.length;i++) {
                char orig=chars[i];
                for (char c='a';c<='z';c++) {
                    chars[i]=c;
                    String next=new String(chars);
                    if (next.equals(endWord)) return level+1;
                    if (wordSet.contains(next)) { q.offer(next); wordSet.remove(next); }
                }
                chars[i]=orig;
            }
        }
        level++;
    }
    return 0;
}

Map<Node,Node> visited = new HashMap<>();
public Node cloneGraph(Node node) {
    if (node==null) return null;
    if (visited.containsKey(node)) return visited.get(node);
    Node clone = new Node(node.val);
    visited.put(node, clone);
    for (Node nb : node.neighbors)
        clone.neighbors.add(cloneGraph(nb));
    return clone;
}

public boolean canFinish(int n, int[][] prereqs) {
    List<List<Integer>> adj = new ArrayList<>();
    for (int i=0;i<n;i++) adj.add(new ArrayList<>());
    for (int[] p:prereqs) adj.get(p[1]).add(p[0]);
    int[] state = new int[n];
    for (int i=0;i<n;i++) if (hasCycle(adj,state,i)) return false;
    return true;
}
boolean hasCycle(List<List<Integer>> adj, int[] state, int v) {
    if (state[v]==1) return true;
    if (state[v]==2) return false;
    state[v]=1;
    for (int nb:adj.get(v)) if (hasCycle(adj,state,nb)) return true;
    state[v]=2;
    return false;
}
